<template>
  <div class="skills">
    <h2 class="skills__title">{{ title }}</h2>
    <div class="skills__container" role="list">
      <div
        class="skill"
        v-for="(hability, index) in habilitiesData"
        :key="index"
        role="listitem"
      >
        <div class="skill__text">
          <span class="skill__name">{{ hability.title }}</span>
          <div
            class="skill__dots"
            :aria-label="calcSkillValue(hability.value)"
          >
            <span
              class="skill__dot"
              :class="{ 'skill__dot--active': hability.value >= 1 }"
            ></span>
            <span
              class="skill__dot"
              :class="{ 'skill__dot--active': hability.value >= 2 }"
            ></span>
            <span
              class="skill__dot"
              :class="{ 'skill__dot--active': hability.value >= 3 }"
            ></span>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";
import { habilitiesData } from "@/Constants";

export default defineComponent({
  props: {
    isSpanish: {
      type: Boolean,
      required: true,
    },
  },
  data() {
    return {
      habilitiesData,
    };
  },
  methods: {
    calcSkillValue(val: number) {
      switch (val) {
        case 1:
          return this.isSpanish ? "Básico" : "Basic";
        case 2:
          return this.isSpanish ? "Intermedio" : "Intermediate";
        case 3:
          return this.isSpanish ? "Avanzado" : "Advanced";
        default:
          return "";
      }
    },
  },
  computed: {
    title: function (): string {
      return this.isSpanish ? "Competencias Técnicas" : "Technical Skills";
    },
  },
});
</script>
